using System;

enum Direction { North, South, East, West }

class Program {
    static void Main() {
        Direction d = Direction.North;
        Console.WriteLine(d);
        Console.WriteLine((int)d);
    }
}

using System;

enum Season { Spring, Summer, Autumn, Winter }

class Program {
    static void Main() {
        Season s = Season.Summer;
        string desc = s switch {
            Season.Spring => "flowers bloom",
            Season.Summer => "hot and sunny",
            Season.Autumn => "leaves fall",
            Season.Winter => "cold and dark"
        };
        Console.WriteLine($"{s}: {desc}");
    }
}

using System;

enum HttpStatus {
    OK = 200,
    Created = 201,
    BadRequest = 400,
    Unauthorized = 401,
    NotFound = 404
}

class Program {
    static void Main() {
        HttpStatus code = HttpStatus.OK;
        Console.WriteLine($"{code} = {(int)code}");
        HttpStatus notFound = (HttpStatus)404;
        Console.WriteLine(notFound);
    }
}

using System;

[Flags]
enum Permissions {
    None   = 0,
    Read   = 1,
    Write  = 2,
    Delete = 4,
    Admin  = Read | Write | Delete
}

class Program {
    static void Main() {
        var perms = Permissions.Read | Permissions.Write;
        Console.WriteLine(perms);
        Console.WriteLine(perms.HasFlag(Permissions.Read));
        Console.WriteLine(perms.HasFlag(Permissions.Delete));
    }
}

using System;

enum Planet { Mercury, Venus, Earth, Mars, Jupiter }

class Program {
    static void Main() {
        foreach (Planet p in Enum.GetValues<Planet>()) {
            Console.WriteLine($"{(int)p}: {p}");
        }
    }
}

using System;

enum Color { Red, Green, Blue }

class Program {
    static void Main() {
        Color c = Enum.Parse<Color>("Green");
        Console.WriteLine(c);

        if (Enum.TryParse<Color>("Purple", out Color bad)) {
            Console.WriteLine(bad);
        } else {
            Console.WriteLine("Purple is not a Color");
        }
    }
}

using System;

enum DayOfWeek2 { Mon, Tue, Wed, Thu, Fri, Sat, Sun }

static class DayExtensions {
    public static bool IsWeekend(this DayOfWeek2 day) =>
        day == DayOfWeek2.Sat || day == DayOfWeek2.Sun;
}

class Program {
    static void Main() {
        foreach (DayOfWeek2 d in Enum.GetValues<DayOfWeek2>()) {
            Console.WriteLine($"{d}: {(d.IsWeekend() ? "weekend" : "weekday")}");
        }
    }
}

using System;

enum Season { Spring, Summer, Autumn, Winter }

class Program {
    static readonly string[] Descriptions = {
        "flowers bloom",
        "hot and sunny",
        "leaves fall",
        "cold and dark"
    };

    static void Main() {
        foreach (Season s in Enum.GetValues<Season>()) {
            Console.WriteLine($"{s}: {Descriptions[(int)s]}");
        }
    }
}
